#include <bits/stdc++.h>
using namespace std;
struct Rode{
    int x,y,t;
}r[100005];
bool cmp(Rode a,Rode b){
    return a.t<b.t;
}
int n,m,f[1003],rest;
int father(int x){
    return (f[x]==x?x:f[x]=father(f[x]));
}
void merge(int x,int y){
    int fx=father(x),fy=father(y);
    if(fx!=fy)
        rest--,f[fy]=fx;
}
int main(){
    scanf("%d%d",&n,&m);
    rest=n;
    for(int i=1;i<=n;i++)
    	f[i]=i;
    for(int i=1;i<=m;i++)
        scanf("%d%d%d",&r[i].x,&r[i].y,&r[i].t);
    sort(r+1,r+m+1,cmp);
    if(rest==1){
        printf("0");
        return 0;
    }
    for(int i=1;i<=m;i++){
        merge(r[i].x,r[i].y);
        if(rest==1){
            printf("%d",r[i].t);
            return 0;
        }
    }
    printf("-1");
    return 0;
}
